class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
def recover_bst(root: TreeNode) -> TreeNode:
    first = second = prev = None
    stack = []
    cur = root
    while cur or stack:
        while cur:
            stack.append(cur)
            cur = cur.left
        cur = stack.pop()
        if prev and cur.val < prev.val:
            if not first:
                first = prev
            second = cur
        prev = cur
        cur = cur.right
    if first and second:
        first.val, second.val = second.val, first.val
    return root

